1	import { type CSSProperties, type JSX, type RefObject, useEffect, useMemo } from 'react';
2	import { Clock } from 'lucide-react';
3	import { Icons } from '@bim-ai/ui';
4	import { WorkspaceSwitcher } from './WorkspaceSwitcher';
5	import type { WorkspaceId } from './workspaces';
6	
7	export interface TopBarV3Props {
8	  // Slot 2
9	  projectName: string;
10	  currentProjectId: string;
11	  onProjectNameClick?: () => void;
12	  projectNameRef?: RefObject<HTMLButtonElement | null>;
13	  // Slot 3 — workspace switcher (CHR-V3-02)
14	  activeWorkspaceId: WorkspaceId;
15	  userPreferredWorkspace: WorkspaceId;
16	  onWorkspaceSwitcherSelect?: (id: WorkspaceId) => void;
17	  // Slot 5
18	  onCommandPalette?: () => void;
19	  // Slot 6
20	  onActivityStream?: () => void;
21	  // Slot 7 — presence
22	  presence?: Array<{ userId: string; name?: string; color?: string }>;
23	  // Slot 8
24	  theme: 'light' | 'dark';
25	  onThemeToggle?: () => void;
26	  onSettings?: () => void;
27	  avatarInitials?: string;
28	  onHamburgerClick?: () => void;
29	}
30	
31	const topBarStyle: CSSProperties = {
32	  height: 'var(--shell-topbar-height)',
33	  minHeight: 'var(--shell-topbar-height)',
34	  backgroundColor: 'var(--color-surface)',
35	  borderBottom: '1px solid var(--color-border)',
36	  borderRadius: 'var(--radius-canvas)',
37	};
38	
39	const MAX_PRESENCE_AVATARS = 4;
40	
41	export function TopBarV3({
42	  projectName,
43	  currentProjectId: _currentProjectId,
44	  onProjectNameClick,
45	  projectNameRef,
46	  activeWorkspaceId,
47	  userPreferredWorkspace,
48	  onWorkspaceSwitcherSelect,
49	  onCommandPalette,
50	  onActivityStream,
51	  presence,
52	  theme,
53	  onThemeToggle,
54	  onSettings,
55	  avatarInitials,
56	  onHamburgerClick,
57	}: TopBarV3Props): JSX.Element {
58	  const isMac = useMemo(() => navigator.platform.toLowerCase().includes('mac'), []);
59	  const cmdGlyph = isMac ? '⌘K' : 'Ctrl+K';
60	
61	  useEffect(() => {
62	    const handler = (e: KeyboardEvent) => {
63	      if ((e.metaKey || e.ctrlKey) && e.key === 'h') {
64	        e.preventDefault();
65	        onActivityStream?.();
66	      }
67	    };
68	    document.addEventListener('keydown', handler);
69	    return () => document.removeEventListener('keydown', handler);
70	  }, [onActivityStream]);
71	
72	  const visiblePresence = presence?.slice(0, MAX_PRESENCE_AVATARS) ?? [];
73	  const overflowCount = Math.max(0, (presence?.length ?? 0) - MAX_PRESENCE_AVATARS);
74	  const hasPresence = (presence?.length ?? 0) > 0;
75	
76	  return (
77	    <div
78	      data-testid="topbar-v3"
79	      role="banner"
80	      style={topBarStyle}
81	      className="flex w-full items-center gap-2 px-2"
82	    >
83	      {/* Hamburger toggle */}
84	      {onHamburgerClick ? (
85	        <button
86	          type="button"
87	          onClick={onHamburgerClick}
88	          aria-label="Toggle navigation"
89	          title="Toggle navigation"
90	          style={{
91	            width: 32,
92	            height: 32,
93	            display: 'flex',
94	            alignItems: 'center',
95	            justifyContent: 'center',
96	            flexShrink: 0,
97	            background: 'none',
98	            border: 'none',
99	            cursor: 'pointer',
100	            borderRadius: 'var(--radius-md)',
101	            color: 'var(--color-muted-foreground)',
102	          }}
103	        >
104	          <Icons.hamburger size={16} aria-hidden="true" />
105	        </button>
106	      ) : null}
107	
108	      {/* Slot 1 — Logo mark */}
109	      <div
110	        role="button"
111	        aria-label="bim-ai home"
112	        tabIndex={0}
113	        onKeyDown={(e) => {
114	          if (e.key === 'Enter' || e.key === ' ') e.currentTarget.click();
115	        }}
116	        style={{
117	          width: 32,
118	          height: 32,
119	          display: 'flex',
120	          alignItems: 'center',
121	          justifyContent: 'center',
122	          flexShrink: 0,
123	          background: 'var(--color-accent)',
124	          borderRadius: 'var(--radius-md)',
125	          color: 'var(--color-surface)',
126	          fontWeight: 700,
127	          fontSize: 'var(--text-xs)',
128	          letterSpacing: '0.04em',
129	          userSelect: 'none',
130	        }}
131	      >
132	        BA
133	      </div>
134	
135	      {/* Slot 2 — Project name */}
136	      <button
137	        type="button"
138	        ref={projectNameRef}
139	        onClick={onProjectNameClick}
140	        aria-haspopup="menu"
141	        data-testid="topbar-v3-project-name"
142	        tabIndex={0}
143	        title={projectName}
144	        style={{
145	          display: 'flex',
146	          alignItems: 'center',
147	          gap: 6,
148	          paddingLeft: 8,
149	          paddingRight: 8,
150	          paddingTop: 4,
151	          paddingBottom: 4,
152	          background: 'none',
153	          border: 'none',
154	          cursor: 'pointer',
155	          fontSize: 'var(--text-sm)',
156	          lineHeight: 'var(--text-sm-line)',
157	          borderRadius: 'var(--radius-md)',
158	          fontWeight: 500,
159	          color: 'var(--color-foreground)',
160	        }}
161	      >
162	        <span
163	          style={{
164	            maxWidth: 180,
165	            overflow: 'hidden',
166	            textOverflow: 'ellipsis',
167	            whiteSpace: 'nowrap',
168	          }}
169	        >
170	          {projectName}
171	        </span>
172	        <Icons.disclosureOpen size={12} aria-hidden="true" />
173	      </button>
174	
175	      {/* Slot 3 — Workspace switcher (CHR-V3-02) */}
176	      <WorkspaceSwitcher
177	        activeWorkspaceId={activeWorkspaceId}
178	        userPreferredWorkspace={userPreferredWorkspace}
179	        onSetActiveWorkspace={onWorkspaceSwitcherSelect ?? (() => undefined)}
180	      />
181	
182	      {/* Slot 4 — Flex stretch; never tools */}
183	      <div style={{ flex: 1 }} aria-hidden="true" />
184	
185	      {/* Slot 5 — Cmd+K palette button */}
186	      <button
187	        type="button"
188	        onClick={onCommandPalette}
189	        aria-keyshortcuts="Meta+K Control+K"
190	        data-testid="topbar-v3-cmdpalette"
191	        tabIndex={0}
192	        title={`Command palette  ${cmdGlyph}`}
193	        style={{
194	          display: 'flex',
195	          alignItems: 'center',
